exercises.solution:
function denormalizeAuthor(posts, users) {
  const userMap = {};
  for (const u of users) userMap[u.id] = u;
  return posts.map(p => {
    const u = userMap[p.authorId];
    return { ...p, author: { name: u.name, avatar: u.avatar } };
  });
}

