exercises.solution:
function queryFilter(docs, filter) {
  return docs.filter(doc => {
    for (const [field, cond] of Object.entries(filter)) {
      if (cond && typeof cond === 'object') {
        if ('$gt' in cond && !(doc[field] > cond.$gt)) return false;
        if ('$lt' in cond && !(doc[field] < cond.$lt)) return false;
        if ('$in' in cond && !cond.$in.includes(doc[field])) return false;
      } else {
        if (doc[field] !== cond) return false;
      }
    }
    return true;
  });
}

