exercises.solution:
function project(doc, projection) {
  const result = {};
  const includeId = projection._id !== 0;
  if (includeId && '_id' in doc) result._id = doc._id;
  for (const [key, val] of Object.entries(projection)) {
    if (key === '_id') continue;
    if (val === 1 && key in doc) result[key] = doc[key];
  }
  return result;
}

