exercises.solution:
function aggregate(docs, pipeline) {
  let stream = [...docs];
  for (const stage of pipeline) {
    if (stage.$match) {
      stream = stream.filter(doc => {
        for (const [f, cond] of Object.entries(stage.$match)) {
          if (cond && typeof cond === 'object') {
            if ('$gte' in cond && !(doc[f] >= cond.$gte)) return false;
            if ('$gt' in cond && !(doc[f] > cond.$gt)) return false;
          } else {
            if (doc[f] !== cond) return false;
          }
        }
        return true;
      });
    } else if (stage.$group) {
      const { _id: groupField, ...accumulators } = stage.$group;
      const map = {};
      for (const doc of stream) {
        const key = doc[groupField];
        if (!map[key]) map[key] = { _id: key };
        for (const [outField, expr] of Object.entries(accumulators)) {
          if (expr.$sum) map[key][outField] = (map[key][outField] || 0) + doc[expr.$sum];
        }
      }
      stream = Object.values(map);
    } else if (stage.$sort) {
      const [field, dir] = Object.entries(stage.$sort)[0];
      stream.sort((a, b) => dir * (a[field] > b[field] ? 1 : a[field] < b[field] ? -1 : 0));
    }
  }
  return stream;
}

