exercises.solution:
function rangeSearch(sortedArr, low, high) {
  let lo = 0, hi = sortedArr.length;
  while (lo < hi) {
    const mid = (lo + hi) >> 1;
    if (sortedArr[mid] < low) lo = mid + 1;
    else hi = mid;
  }
  const result = [];
  for (let i = lo; i < sortedArr.length && sortedArr[i] <= high; i++) {
    result.push(sortedArr[i]);
  }
  return result;
}

