exercises.solution:
function cacheAside(cache, key, fetchFn, ttl) {
  const entry = cache[key];
  if (entry && entry.expiresAt > Date.now()) return entry.value;
  const value = fetchFn();
  cache[key] = { value, expiresAt: Date.now() + ttl };
  return value;
}

