exercises.solution:
function innerJoin(left, right, leftKey, rightKey) {
  const result = [];
  for (const l of left) {
    for (const r of right) {
      if (l[leftKey] === r[rightKey]) result.push({ ...l, ...r });
    }
  }
  return result;
}

