const users = [{ id: 1, name: 'A' }, { id: 2, name: 'B' }, { id: 3, name: 'C' }];
const allPosts = [{ id: 10, userId: 1, title: 'p1' }, { id: 11, userId: 2, title: 'p2' }, { id: 12, userId: 1, title: 'p3' }];
let n1Calls = 0;
const queryPost = (uid) => { n1Calls++; return allPosts.filter(p => p.userId === uid); };
let batchCalls = 0;
const queryPosts = (uids) => { batchCalls++; return allPosts.filter(p => uids.includes(p.userId)); };
const r1 = fetchWithN1(users, queryPost);
check('N+1 makes 3 calls', () => expect(n1Calls).toBe(3));
check('N+1 user 1 has 2 posts', () => expect(r1.find(u => u.id === 1).posts.length).toBe(2));
const r2 = fetchBatched(users, queryPosts);
check('batched makes 1 call', () => expect(batchCalls).toBe(1));
check('batched user 2 has 1 post', () => expect(r2.find(u => u.id === 2).posts.length).toBe(1));
check('batched user 3 has 0 posts', () => expect(r2.find(u => u.id === 3).posts.length).toBe(0));

exercises.solution:
function fetchWithN1(users, queryPost) {
  return users.map(u => ({ ...u, posts: queryPost(u.id) }));
}

function fetchBatched(users, queryPosts) {
  const ids = users.map(u => u.id);
  const posts = queryPosts(ids);
  const postsByUser = {};
  for (const p of posts) (postsByUser[p.userId] = postsByUser[p.userId] || []).push(p);
  return users.map(u => ({ ...u, posts: postsByUser[u.id] || [] }));
}

